mapper.select:
SELECT w.waybillid, w.status, w.total_freight, w.create_date, w.priority, w.clerk,
       c.name AS destination_city, r.name AS destination_region,
       COALESCE(SUM(i.quantity), 0) AS item_quantity
FROM waybill w
JOIN city c ON c.cityid = w.destination_cityid
JOIN hub_region r ON r.regionid = c.regionid
LEFT JOIN waybill_item i ON i.waybillid = w.waybillid


        AND w.status = #{status}


        AND r.regionid = #{regionId}


        AND w.create_date >= #{start}


        AND w.create_date < #{end}


GROUP BY w.waybillid, w.status, w.total_freight, w.create_date, w.priority, w.clerk, c.name, r.name
ORDER BY w.create_date DESC

mapper.update:
UPDATE inventory
SET quantity = quantity - #{quantity}, frozen_quantity = frozen_quantity + #{quantity}
WHERE whid = #{whId} AND goodsid = #{goodsId} AND quantity >= #{quantity}

UPDATE inventory
SET quantity = quantity + #{quantity}, frozen_quantity = frozen_quantity - #{quantity}
WHERE whid = #{whId} AND goodsid = #{goodsId} AND frozen_quantity >= #{quantity}

UPDATE inventory
SET frozen_quantity = frozen_quantity - #{quantity}
WHERE whid = #{whId} AND goodsid = #{goodsId} AND frozen_quantity >= #{quantity}
